import vex
from google.adk import Agent, before_agent_callback

@vex.guardrail
def check_hiring_bias(inputs: dict, outputs: dict) -> bool:
    protected_terms = ['race', 'gender', 'age', 'disability']
    output_text = str(outputs).lower()
    return not any(term in output_text for term in protected_terms)

# Install: pip install google-adk vex-sdk
agent = Agent(
    name="ResumeScreeningAgent",
    before_agent_callback=before_agent_callback(check_hiring_bias)
)

result = agent.run({"resume": "John Doe, Harvard, 5 years exp"})

@vex.guardrail(log_audit=True, sensitivity='high-risk')
def ensure_disclosure(candidate_id: str, decision: str) -> dict:
    audit_log = {
        'timestamp': vex.now(),
        'candidate_id': candidate_id,
        'decision': decision,
        'ai_used': True,
        'agents_involved': vex.current_session().get('agents', [])
    }
    vex.log_audit('hiring_decision', audit_log)
    disclosure_msg = f"This decision was made using Google ADK AI agents: {audit_log['agents_involved']}"
    return {'decision': decision, 'disclosure': disclosure_msg}

screening_result = ensure_disclosure('cand_123', 'advance_to_interview')
